import React from "react";
import { useNavigate } from "react-router-dom";

function LandingPage() {
  const navigate = useNavigate();

  return (
    <div style={styles.container}>

      {/* Logo */}
      <h1 style={styles.logo}>DocBook</h1>

      {/* Content */}
      <h2 style={styles.title}>Welcome to DocBook</h2>

      <p style={styles.subtitle}>
        Book doctor appointments بسهولة and manage your health easily.
      </p>

      {/* Buttons */}
      <div style={styles.buttons}>
        <button style={styles.loginBtn} onClick={() => navigate("/login")}>
          Login
        </button>

        <button style={styles.registerBtn} onClick={() => navigate("/register")}>
          Register
        </button>
      </div>

    </div>
  );
}

export default LandingPage;

const styles = {
  container: {
    height: "100vh",
    background: "linear-gradient(135deg, #2563EB, #1E40AF)",
    display: "flex",
    flexDirection: "column",
    justifyContent: "center",
    alignItems: "center",
    color: "white",
    textAlign: "center",
  },

  logo: {
    fontSize: "32px",
    marginBottom: "10px",
  },

  title: {
    fontSize: "28px",
    marginBottom: "10px",
  },

  subtitle: {
    maxWidth: "400px",
    marginBottom: "30px",
  },

  buttons: {
    display: "flex",
    gap: "15px",
  },

  loginBtn: {
    padding: "10px 20px",
    border: "none",
    borderRadius: "6px",
    backgroundColor: "white",
    color: "#2563EB",
    cursor: "pointer",
  },

  registerBtn: {
    padding: "10px 20px",
    border: "none",
    borderRadius: "6px",
    backgroundColor: "#10B981",
    color: "white",
    cursor: "pointer",
  },
};
